               feedback_at = NOW()
           WHERE message_id = ${sq(body.message_id)}
           RETURNING id, message_id, feedback_status`;
    break;
  }

  case 'internal_knowledge_list': {
    sql = `SELECT il.id, il.message_id, il.deal_id, il.subject, il.sender_email,
             il.sender_domain, il.doc_type, il.chunk_count, il.ingested_at,
