  il.id, il.message_id, il.deal_id, il.subject, il.sender_email,
  il.sender_domain, il.doc_type, il.attachment_count, il.chunk_count,
  il.attribution_confidence, il.attribution_status, il.ingested_at,
  il.qdrant_namespace,
  il.classification_reasoning,
  il.classification_feedback,
  il.doc_type_override,
  il.deal_id_override,
  il.feedback_status,
  il.feedback_at,
  d.company_name,
  d.status as deal_status
FROM ingestion_log il
LEFT JOIN deals d ON d.deal_id = il.deal_id
ORDER BY il.ingested_at DESC
LIMIT 500`;
    break;

  case 'pipeline_summary':
    sql = `SELECT d.deal_stage, d.forecast_category,
             COUNT(*) AS deal_count,
             SUM(d.deal_value_usd) AS total_value,
             ROUND(AVG(dh.p2v2c2_total), 1) AS avg_p2v2c2,
             COUNT(CASE WHEN dh.trend_direction = 'declining' THEN 1 END) AS declining_deals
           FROM deals d
           LEFT JOIN LATERAL (
             SELECT * FROM deal_health WHERE deal_id = d.deal_id ORDER BY scored_at DESC LIMIT 1
           ) dh ON true
           WHERE d.is_active = true
           GROUP BY d.deal_stage, d.forecast_category
           ORDER BY d.deal_stage`;
    break;

  case 'confirm_attribution':
    const msgId = body.message_id || null;
    const resolvedDealId = body.resolved_deal_id || null;
    const resolution = body.resolution || 'confirmed';
    if (!msgId) throw new Error('confirm_attribution requires message_id');
    sql = `UPDATE attribution_queue
           SET resolution = '${resolution}',
               resolved_deal_id = ${resolvedDealId ? `'${resolvedDealId}'` : 'NULL'},
               resolved_at = NOW()
           WHERE message_id = '${msgId}'
           RETURNING id, message_id, resolution, resolved_deal_id`;
    break;

  case 'error_status':
    sql = `SELECT COUNT(*) as cnt, COALESCE(MAX(severity), 'none') as max_sev FROM workflow_errors WHERE acknowledged = FALSE`;
    break;


  case 'scoring_history':
    if (!dealId) throw new Error('scoring_history requires deal_id');
    sql = `SELECT scored_at, trigger_type,
             pain_score, power_score, vision_score, value_score, change_score, control_score,
             critical_activity_stage, general_narrative, call_summary,
             pain_justification, power_justification, vision_justification,
             value_justification, change_justification, control_justification,
             trigger_message_id
           FROM deal_health
           WHERE deal_id = ${sq(dealId)}
           ORDER BY scored_at DESC
           LIMIT 50`;
    break;

  case 'activity_timeline':
    if (!dealId) throw new Error('activity_timeline requires deal_id');
    sql = `SELECT
             'notification' AS event_type,
             created_at AS event_time,
             notification_type AS sub_type,
             summary,
             context::text AS context,
             NULL AS message_id
           FROM deal_notifications
           WHERE deal_id = ${sq(dealId)}
           UNION ALL
           SELECT
             'ingestion' AS event_type,
             ingested_at AS event_time,
             doc_type AS sub_type,
             COALESCE(subject, doc_type) AS summary,
             json_build_object('sender', sender_email, 'chunks', chunk_count, 'attribution', attribution_status)::text AS context,
             message_id
           FROM ingestion_log
           WHERE deal_id = ${sq(dealId)}
           UNION ALL
           SELECT
             CASE
               WHEN status = 'dismissed' THEN 'draft_dismissed'
               WHEN status = 'approved' THEN 'draft_approved'
               WHEN status = 'sent' THEN 'output'
               ELSE 'output'
             END AS event_type,
             sent_at AS event_time,
             output_type AS sub_type,
             COALESCE(subject, output_type) AS summary,
             json_build_object('recipient', recipient_email, 'status', status, 'dismiss_reason', dismiss_reason)::text AS context,
             NULL AS message_id
           FROM outputs_log
           WHERE deal_id = ${sq(dealId)}
           ORDER BY event_time DESC
           LIMIT 100`;
    break;

  case 'deal_documents':
    if (!dealId) throw new Error('deal_documents requires deal_id');
    sql = `SELECT message_id, deal_id, doc_type, subject, sender_email, sender_domain,
             chunk_count, ingested_at, attribution_status, classification_reasoning
           FROM ingestion_log
           WHERE deal_id = ${sq(dealId)}
           ORDER BY ingested_at DESC
           LIMIT 100`;
    break;

  case 'reassign_document': {
    const messageId = body.message_id;
    const fromDealId = body.from_deal_id;
    const toDealId = body.to_deal_id;
    if (!messageId || !toDealId) throw new Error('reassign_document requires message_id and to_deal_id');
    sql = `UPDATE ingestion_log SET deal_id = ${sq(toDealId)}, attribution_status = 'reassigned'
           WHERE message_id = ${sq(messageId)}
           RETURNING id, message_id, deal_id`;
    break;
  }

  case 'remove_document': {
    const msgId2 = body.message_id;
    const removeDealId = body.deal_id;
    if (!msgId2) throw new Error('remove_document requires message_id');
    sql = `UPDATE ingestion_log SET deal_id = NULL, attribution_status = 'removed'
           WHERE message_id = ${sq(msgId2)}
           RETURNING id, message_id, deal_id`;
    break;
  }

  case 'revert_score': {
    const triggerMsgId = body.trigger_message_id;
    if (!triggerMsgId) throw new Error('revert_score requires trigger_message_id');
    sql = `DELETE FROM deal_health WHERE trigger_message_id = ${sq(triggerMsgId)} RETURNING id, deal_id, scored_at`;
    break;
  }

  case 'update_deal_status': {
    const targetDealId = body.deal_id;
    const newStatus = body.status;
    if (!targetDealId || !newStatus) throw new Error('update_deal_status requires deal_id and status');
    if (!['active','internal','archived'].includes(newStatus)) throw new Error('Invalid status value');
    const isActive = newStatus === 'active' ? 'true' : 'false';
    sql = `UPDATE deals SET status = ${sq(newStatus)}, is_active = ${isActive}, updated_at = NOW()
           WHERE deal_id = ${sq(targetDealId)}
           RETURNING deal_id, status, is_active`;
    break;
  }

  case 'ingestion_feedback': {
    if (!body.message_id) throw new Error('ingestion_feedback requires message_id');
    sql = `UPDATE ingestion_log
           SET feedback_status = ${sq(body.feedback_status)},
               classification_feedback = ${sq(body.classification_feedback)},
               feedback_at = NOW()
           WHERE message_id = ${sq(body.message_id)}
           RETURNING id, message_id, feedback_status`;
    break;
  }

  case 'ingestion_doc_type_override': {
    if (!body.message_id) throw new Error('ingestion_doc_type_override requires message_id');
    sql = `UPDATE ingestion_log
           SET doc_type_override = ${sq(body.doc_type_override)},
               feedback_status = 'incorrect',
               classification_feedback = COALESCE(${sq(body.classification_feedback)}, classification_feedback),
               feedback_at = NOW()
           WHERE message_id = ${sq(body.message_id)}
           RETURNING id, message_id, doc_type_override, feedback_status`;
    break;
  }

  case 'ingestion_reassign': {
    if (!body.message_id || !body.new_deal_id) throw new Error('ingestion_reassign requires message_id and new_deal_id');
    sql = `UPDATE ingestion_log
           SET deal_id_override = ${sq(body.new_deal_id)},
               deal_id = ${sq(body.new_deal_id)},
               qdrant_namespace = ${sq(body.new_deal_id)},
               feedback_status = 'incorrect',
               classification_feedback = COALESCE(${sq(body.classification_feedback)}, classification_feedback),
               feedback_at = NOW()
           WHERE message_id = ${sq(body.message_id)}
           RETURNING id, message_id, deal_id, deal_id_override, feedback_status`;
    break;
  }

  case 'move_to_internal': {
    if (!body.message_id) throw new Error('move_to_internal requires message_id');
    sql = `UPDATE ingestion_log
           SET feedback_status = 'moved_to_internal',
               classification_feedback = COALESCE(${sq(body.classification_feedback)}, classification_feedback),
               feedback_at = NOW()
           WHERE message_id = ${sq(body.message_id)}
           RETURNING id, message_id, feedback_status`;
    break;
  }

  case 'internal_knowledge_list': {
    sql = `SELECT il.id, il.message_id, il.deal_id, il.subject, il.sender_email,
             il.sender_domain, il.doc_type, il.chunk_count, il.ingested_at,
             il.classification_feedback, il.feedback_at,
             d.company_name
           FROM ingestion_log il
           LEFT JOIN deals d ON d.deal_id = il.deal_id
           WHERE il.feedback_status = 'moved_to_internal'
           ORDER BY il.feedback_at DESC
           LIMIT 200`;
    break;
  }

  case 'kb_list': {
    sql = `SELECT id, title, category, tags, summary, source_type, source_ref,
             original_deal_id, original_subject, chunk_count, reference_count,
             created_at, updated_at, is_deleted
           FROM internal_knowledge
           WHERE is_deleted = FALSE
           ORDER BY created_at DESC
           LIMIT 200`;
    break;
  }

  case 'kb_insert': {
    sql = `INSERT INTO internal_knowledge (title, category, tags, summary, source_type, source_ref, original_deal_id, original_subject, message_id, chunk_count)
           VALUES (${sq(body.title)}, ${sq(body.category)}, ${body.tags ? "ARRAY[" + body.tags.map(t => sq(t)).join(",") + "]" : "'{}'"}, ${sq(body.summary)}, ${sq(body.source_type)}, ${sq(body.source_ref)}, ${sq(body.original_deal_id)}, ${sq(body.original_subject)}, ${sq(body.message_id)}, ${body.chunk_count || 1})
           RETURNING id`;
    break;
  }

  case 'kb_update': {
    sql = `UPDATE internal_knowledge
           SET title = COALESCE(${sq(body.title)}, title),
               category = COALESCE(${sq(body.category)}, category),
               tags = ${body.tags ? "ARRAY[" + body.tags.map(t => sq(t)).join(",") + "]" : "tags"},
               summary = COALESCE(${sq(body.summary)}, summary),
               updated_at = NOW()
           WHERE id = ${parseInt(body.id)}`;
    break;
  }

  case 'kb_delete': {
    sql = `UPDATE internal_knowledge SET is_deleted = TRUE, updated_at = NOW() WHERE id = ${parseInt(body.id)}`;
    break;
  }

  case 'kb_stats': {
    sql = `SELECT category, COUNT(*) as count FROM internal_knowledge WHERE is_deleted = FALSE GROUP BY category ORDER BY count DESC`;
    break;
  }

  case 'create_priority': {
    if (!body.project_name) throw new Error('create_priority requires project_name');
    const slug = body.project_name.toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
    const dealId = 'int_' + slug + '_' + new Date().getFullYear();
    sql = `INSERT INTO deals (deal_id, company_name, deal_stage, deal_owner, is_active, status)
           VALUES (${sq(dealId)}, ${sq(body.project_name)}, 'active', 'austin.holland@clearwatersecurity.com', true, 'internal')
           ON CONFLICT (deal_id) DO NOTHING
           RETURNING deal_id, company_name`;
    break;
  }


  case 'dismiss_draft': {
    const draftId = parseInt(body.draft_id || body.id, 10);
    const reason = (body.dismiss_reason || '').substring(0, 500);
    if (!draftId) throw new Error('dismiss_draft requires draft_id');
    sql = `UPDATE outputs_log SET status = 'dismissed', dismiss_reason = ${sq(reason)} WHERE id = ${draftId} RETURNING id, status, dismiss_reason`;
    break;
  }

  case 'output_feedback': {
    const feedback = (body.feedback || '').substring(0, 500);
    const summary = body.summary || '';
    if (!dealId) throw new Error('output_feedback requires deal_id');
    if (!feedback) throw new Error('output_feedback requires feedback');
    sql = `UPDATE outputs_log SET dismiss_reason = COALESCE(dismiss_reason, '') || ' [FEEDBACK: ' || ${sq(feedback)} || ']' WHERE deal_id = ${sq(dealId)} AND (subject = ${sq(summary)} OR content_summary = ${sq(summary)}) AND sent_at = (SELECT MAX(sent_at) FROM outputs_log WHERE deal_id = ${sq(dealId)} AND (subject = ${sq(summary)} OR content_summary = ${sq(summary)})) RETURNING id, dismiss_reason`;
    break;
  }


  case 'remove_stakeholder': {
    if (!dealId) throw new Error('remove_stakeholder requires deal_id');
    const stakeholderName = body.stakeholder_name;
    if (!stakeholderName) throw new Error('remove_stakeholder requires stakeholder_name');
    sql = `DELETE FROM deal_stakeholders WHERE deal_id = ${sq(dealId)} AND name = ${sq(stakeholderName)} AND scored_at = (SELECT MAX(scored_at) FROM deal_stakeholders WHERE deal_id = ${sq(dealId)} AND name = ${sq(stakeholderName)}) RETURNING name, deal_id`;
    break;
  }

  default:
    throw new Error(`Unknown query_type: ${queryType}`);
}

return [{ json: { query_type: queryType, sql, deal_id: dealId, is_qdrant: false } }];

// Collect all rows and return as a clean JSON array
const rows = $input.all().map(item => item.json);
const queryType = $('Code: Route Query').first().json.query_type;

return [{
  json: {
    query_type: queryType,
    row_count: rows.length,
    rows
  }
}];

// Build the Qdrant scroll request for chunks_by_message_id
// Supports two lookup strategies:
// 1. Live-ingested content: has message_id in Qdrant payload
// 2. Backfilled content: has source_file in Qdrant payload (no message_id)
const input = $input.first().json;
let messageId = input.message_id || '';
const sourceFile = input.source_file || '';
const dealId = input.deal_id || '';

// Strip _att_<filename> suffix — ingestion_log stores it but Qdrant uses base message_id
messageId = messageId.replace(/_att_.*$/, '');

// Detect backfilled content: MD5 hashes (32 hex), bf-prefixed, or _dup_ suffixed
const isMd5 = /^[a-f0-9]{32}$/i.test(messageId) || /^bf[a-f0-9]{30}$/i.test(messageId) || /_dup_/.test(messageId);

// Detect if source_file looks like an actual filename vs a calendar/email subject
// Real filenames end with extensions: .txt, .eml, .pdf, .pptx, .csv, .xlsx, etc.
const looksLikeFilename = /\.[a-z0-9]{2,5}$/i.test(sourceFile);

let filter;
if (isMd5 && sourceFile && looksLikeFilename) {
  // Backfilled with valid filename: query by source_file, scoped to deal_id
  const must = [{ key: 'source_file', match: { value: sourceFile } }];
  if (dealId) must.push({ key: 'deal_id', match: { value: dealId } });
  filter = { must };
} else if (isMd5 && dealId) {
  // Backfilled but source_file is not a filename (e.g. calendar title, email subject)
  // Fall back to deal_id-only query — returns all chunks for this deal
  filter = { must: [{ key: 'deal_id', match: { value: dealId } }] };
} else if (sourceFile && looksLikeFilename) {
  // Has both — use should (OR) to match either way
  const shouldClauses = [
    { key: 'message_id', match: { value: messageId } },
    { key: 'source_file', match: { value: sourceFile } }
  ];
  const must = dealId ? [{ key: 'deal_id', match: { value: dealId } }] : [];
  filter = { should: shouldClauses, must };
} else {
  // Original behavior: match by message_id only
  filter = { must: [{ key: 'message_id', match: { value: messageId } }] };
}

const qdrantBody = { filter, limit: 100, with_payload: true, with_vector: false };

return [{ json: { qdrant_body: qdrantBody, message_id: messageId } }];

// Transform Qdrant scroll response into clean chunks array
const response = $input.first().json;
const points = response.result && response.result.points ? response.result.points : [];

const chunks = points.map(p => ({
  chunk_index: p.payload.chunk_index != null ? p.payload.chunk_index : 0,
  page_content: p.payload.page_content || p.payload.text || '',
  doc_type: p.payload.doc_type || 'unknown',
  date_created: p.payload.date_created || null,
  deal_id: p.payload.deal_id || null
})).sort((a, b) => a.chunk_index - b.chunk_index);

return [{
  json: {
    query_type: 'chunks_by_message_id',
    row_count: chunks.length,
    rows: chunks
  }
}];
